1689	    return scan;
1690	}
1691	
1692	/*
1693	Finds the longest match (length and corresponding distance) for LZ77
1694	compression.
1695	Even when not using "sublen", it can be more efficient to provide an array,
1696	because only then the caching is used.
1697	array: the data
1698	pos: position in the data to find the match for
1699	size: size of the data
1700	limit: limit length to maximum this value (default should be 258). This allows
1701	finding a shorter dist for that length (= less extra bits). Must be
1702	in the range [ZOPFLI_MIN_MATCH, ZOPFLI_MAX_MATCH].
1703	sublen: output array of 259 elements, or null. Has, for each length, the
1704	smallest distance required to reach this length. Only 256 of its 259 values
1705	are used, the first 3 are ignored (the shortest length is 3. It is purely
1706	for convenience that the array is made 3 longer).
1707	*/
1708	void ZopfliFindLongestMatch(ZopfliBlockState *s, const ZopfliHash *h,
1709	                            const unsigned char *array,
1710	                            size_t pos, size_t size, size_t limit,
1711	                            unsigned short *sublen, unsigned short *distance, unsigned short *length)
1712	{
1713	    unsigned short hpos = pos & ZOPFLI_WINDOW_MASK, p, pp;
1714	    unsigned short bestdist = 0;
1715	    unsigned short bestlength = 1;
1716	    const unsigned char *scan;
1717	    const unsigned char *match;
1718	    const unsigned char *arrayend;
1719	    const unsigned char *arrayend_safe;
1720	    int chain_counter = ZOPFLI_MAX_CHAIN_HITS; /* For quitting early. */
1721	
1722	    unsigned dist = 0; /* Not unsigned short on purpose. */
1723	
1724	    int *hhead = h->head;
1725	    unsigned short *hprev = h->prev;
1726	    int *hhashval = h->hashval;
1727	    int hval = h->val;
1728	
1729	    if (TryGetFromLongestMatchCache(s, pos, &limit, sublen, distance, length))
1730	    {
1731	        assert(pos + *length <= size);
1732	        return;
1733	    }
1734	
1735	    assert(limit <= ZOPFLI_MAX_MATCH);
1736	    assert(limit >= ZOPFLI_MIN_MATCH);
1737	    assert(pos < size);
1738	
1739	    if (size - pos < ZOPFLI_MIN_MATCH)
1740	    {
1741	        /* The rest of the code assumes there are at least ZOPFLI_MIN_MATCH bytes to
1742	           try. */
1743	        *length = 0;
1744	        *distance = 0;
1745	        return;
1746	    }
1747	
1748	    if (pos + limit > size)
1749	    {
1750	        limit = size - pos;
1751	    }
1752	    arrayend = &array[pos] + limit;
1753	    arrayend_safe = arrayend - 8;
1754	
1755	    assert(hval < 65536);
1756	
1757	    pp = hhead[hval]; /* During the whole loop, p == hprev[pp]. */
1758	    p = hprev[pp];
1759	
1760	    assert(pp == hpos);
1761	
1762	    dist = p < pp ? pp - p : ((ZOPFLI_WINDOW_SIZE - p) + pp);
1763	
1764	    /* Go through all distances. */
1765	    while (dist < ZOPFLI_WINDOW_SIZE)
1766	    {
1767	        unsigned short currentlength = 0;
1768	
1769	        assert(p < ZOPFLI_WINDOW_SIZE);
1770	        assert(p == hprev[pp]);
1771	        assert(hhashval[p] == hval);
1772	
1773	        if (dist > 0)
1774	        {
1775	            assert(pos < size);
1776	            assert(dist <= pos);
1777	            scan = &array[pos];
1778	            match = &array[pos - dist];
1779	
1780	            /* Testing the byte at position bestlength first, goes slightly faster. */
1781	            if (pos + bestlength >= size || *(scan + bestlength) == *(match + bestlength))
1782	            {
1783	
1784	                unsigned short same0 = h->same[pos & ZOPFLI_WINDOW_MASK];
1785	                if (same0 > 2 && *scan == *match)
1786	                {
1787	                    unsigned short same1 = h->same[(pos - dist) & ZOPFLI_WINDOW_MASK];
1788	                    unsigned short same = same0 < same1 ? same0 : same1;
1789	                    if (same > limit)
1790	                        same = limit;
1791	                    scan += same;
1792	                    match += same;
1793	                }
1794	                scan = GetMatch(scan, match, arrayend, arrayend_safe);
1795	                currentlength = scan - &array[pos]; /* The found length. */
1796	            }
1797	
1798	            if (currentlength > bestlength)
1799	            {
1800	                if (sublen)
1801	                {
1802	                    unsigned short j;
1803	                    for (j = bestlength + 1; j <= currentlength; j++)
1804	                    {
1805	                        sublen[j] = dist;
1806	                    }
1807	                }
1808	                bestdist = dist;
1809	                bestlength = currentlength;
1810	                if (currentlength >= limit)
1811	                    break;
1812	            }
1813	        }
1814	
1815	        /* Switch to the other hash once this will be more efficient. */
1816	        if (hhead != h->head2 && bestlength >= h->same[hpos] &&
1817	            h->val2 == h->hashval2[p])
1818	        {
1819	            /* Now use the hash that encodes the length and first byte. */
1820	            hhead = h->head2;
1821	            hprev = h->prev2;
1822	            hhashval = h->hashval2;
1823	            hval = h->val2;
1824	        }
1825	
1826	        pp = p;
1827	        p = hprev[p];
1828	        if (p == pp)
1829	            break; /* Uninited prev value. */
1830	
1831	        dist += p < pp ? pp - p : ((ZOPFLI_WINDOW_SIZE - p) + pp);
1832	
1833	        chain_counter--;
1834	        if (chain_counter <= 0)
1835	            break;
1836	    }
1837	
1838	    StoreInLongestMatchCache(s, pos, limit, sublen, bestdist, bestlength);
1839	
1840	    assert(bestlength <= limit);
1841	
1842	    *distance = bestdist;
1843	    *length = bestlength;
1844	    assert(pos + *length <= size);
1845	}
