1847	/*
1848	Verifies if length and dist are indeed valid, only used for assertion.
1849	*/
1850	void ZopfliVerifyLenDist(const unsigned char *data, size_t datasize, size_t pos,
1851	                         unsigned short dist, unsigned short length)
1852	{
1853	
1854	    /* TODO(lode): make this only run in a debug compile, it's for assert only. */
1855	    size_t i;
1856	
1857	    assert(pos + length <= datasize);
1858	    for (i = 0; i < length; i++)
1859	    {
1860	        if (data[pos - dist + i] != data[pos + i])
1861	        {
1862	            assert(data[pos - dist + i] == data[pos + i]);
1863	            break;
1864	        }
1865	    }
1866	}
