1868	#define HASH_MASK 32767
1869	
1870	#define HASH_SHIFT 5
1871	
1872	/*
1873	Update the sliding hash value with the given byte. All calls to this function
1874	must be made on consecutive input characters. Since the hash value exists out
1875	of multiple input bytes, a few warmups with this function are needed initially.
1876	*/
1877	static void UpdateHashValue(ZopfliHash *h, unsigned char c)
1878	{
1879	    h->val = (((h->val) << HASH_SHIFT) ^ (c)) & HASH_MASK;
1880	}
1881	
1882	/*
1883	Prepopulates hash:
1884	Fills in the initial values in the hash, before ZopfliUpdateHash can be used
1885	correctly.
1886	*/
1887	void ZopfliWarmupHash(const unsigned char *array, size_t pos, size_t end,
1888	                      ZopfliHash *h)
1889	{
1890	    UpdateHashValue(h, array[pos + 0]);
1891	    if (pos + 1 < end)
1892	        UpdateHashValue(h, array[pos + 1]);
1893	}
