1895	/*
1896	Appends the length and distance to the LZ77 arrays of the ZopfliLZ77Store.
1897	context must be a ZopfliLZ77Store*.
1898	*/
1899	void ZopfliStoreLitLenDist(unsigned short length, unsigned short dist,
1900	                           size_t pos, ZopfliLZ77Store *store)
1901	{
1902	    size_t i;
1903	    /* Needed for using ZOPFLI_APPEND_DATA multiple times. */
1904	    size_t origsize = store->size;
1905	    size_t llstart = ZOPFLI_NUM_LL * (origsize / ZOPFLI_NUM_LL);
1906	    size_t dstart = ZOPFLI_NUM_D * (origsize / ZOPFLI_NUM_D);
1907	
1908	    /* Everytime the index wraps around, a new cumulative histogram is made: we're
1909	    keeping one histogram value per LZ77 symbol rather than a full histogram for
1910	    each to save memory. */
1911	    if (origsize % ZOPFLI_NUM_LL == 0)
1912	    {
1913	        size_t llsize = origsize;
1914	        for (i = 0; i < ZOPFLI_NUM_LL; i++)
1915	        {
1916	            ZOPFLI_APPEND_DATA(
1917	                origsize == 0 ? 0 : store->ll_counts[origsize - ZOPFLI_NUM_LL + i],
1918	                &store->ll_counts, &llsize);
1919	        }
1920	    }
1921	    if (origsize % ZOPFLI_NUM_D == 0)
1922	    {
1923	        size_t dsize = origsize;
1924	        for (i = 0; i < ZOPFLI_NUM_D; i++)
1925	        {
1926	            ZOPFLI_APPEND_DATA(
1927	                origsize == 0 ? 0 : store->d_counts[origsize - ZOPFLI_NUM_D + i],
1928	                &store->d_counts, &dsize);
1929	        }
1930	    }
1931	
1932	    ZOPFLI_APPEND_DATA(length, &store->litlens, &store->size);
1933	    store->size = origsize;
1934	    ZOPFLI_APPEND_DATA(dist, &store->dists, &store->size);
1935	    store->size = origsize;
1936	    ZOPFLI_APPEND_DATA(pos, &store->pos, &store->size);
1937	    assert(length < 259);
1938	
1939	    if (dist == 0)
1940	    {
1941	        store->size = origsize;
1942	        ZOPFLI_APPEND_DATA(length, &store->ll_symbol, &store->size);
1943	        store->size = origsize;
1944	        ZOPFLI_APPEND_DATA(0, &store->d_symbol, &store->size);
1945	        store->ll_counts[llstart + length]++;
1946	    }
1947	    else
1948	    {
1949	        store->size = origsize;
1950	        ZOPFLI_APPEND_DATA(ZopfliGetLengthSymbol(length),
1951	                           &store->ll_symbol, &store->size);
1952	        store->size = origsize;
1953	        ZOPFLI_APPEND_DATA(ZopfliGetDistSymbol(dist),
1954	                           &store->d_symbol, &store->size);
1955	        store->ll_counts[llstart + ZopfliGetLengthSymbol(length)]++;
1956	        store->d_counts[dstart + ZopfliGetDistSymbol(dist)]++;
1957	    }
1958	}
1959	
1960	void ZopfliUpdateHash(const unsigned char *array, size_t pos, size_t end,
1961	                      ZopfliHash *h)
1962	{
1963	    unsigned short hpos = pos & ZOPFLI_WINDOW_MASK;
1964	    size_t amount = 0;
1965	
1966	    UpdateHashValue(h, pos + ZOPFLI_MIN_MATCH <= end ? array[pos + ZOPFLI_MIN_MATCH - 1] : 0);
1967	    h->hashval[hpos] = h->val;
1968	    if (h->head[h->val] != -1 && h->hashval[h->head[h->val]] == h->val)
1969	    {
1970	        h->prev[hpos] = h->head[h->val];
1971	    }
1972	    else
1973	        h->prev[hpos] = hpos;
1974	    h->head[h->val] = hpos;
1975	
1976	    /* Update "same". */
1977	    if (h->same[(pos - 1) & ZOPFLI_WINDOW_MASK] > 1)
1978	    {
1979	        amount = h->same[(pos - 1) & ZOPFLI_WINDOW_MASK] - 1;
1980	    }
1981	    while (pos + amount + 1 < end &&
1982	           array[pos] == array[pos + amount + 1] && amount < (unsigned short)(-1))
1983	    {
1984	        amount++;
1985	    }
1986	    h->same[hpos] = amount;
1987	
1988	    h->val2 = ((h->same[hpos] - ZOPFLI_MIN_MATCH) & 255) ^ h->val;
1989	    h->hashval2[hpos] = h->val2;
1990	    if (h->head2[h->val2] != -1 && h->hashval2[h->head2[h->val2]] == h->val2)
1991	    {
1992	        h->prev2[hpos] = h->head2[h->val2];
1993	    }
1994	    else
1995	        h->prev2[hpos] = hpos;
1996	    h->head2[h->val2] = hpos;
1997	}
1998	
1999	void ZopfliResetHash(size_t window_size, ZopfliHash *h)
2000	{
2001	    size_t i;
2002	
2003	    h->val = 0;
2004	    for (i = 0; i < 65536; i++)
2005	    {
2006	        h->head[i] = -1; /* -1 indicates no head so far. */
2007	    }
2008	    for (i = 0; i < window_size; i++)
2009	    {
2010	        h->prev[i] = i; /* If prev[j] == j, then prev[j] is uninitialized. */
2011	        h->hashval[i] = -1;
2012	    }
2013	
2014	    for (i = 0; i < window_size; i++)
2015	    {
2016	        h->same[i] = 0;
2017	    }
2018	
2019	    h->val2 = 0;
2020	    for (i = 0; i < 65536; i++)
2021	    {
2022	        h->head2[i] = -1;
2023	    }
2024	    for (i = 0; i < window_size; i++)
2025	    {
2026	        h->prev2[i] = i;
2027	        h->hashval2[i] = -1;
2028	    }
2029	}
2030	
2031	static void FollowPath(ZopfliBlockState *s,
2032	                       const unsigned char *in, size_t instart, size_t inend,
2033	                       unsigned short *path, size_t pathsize,
2034	                       ZopfliLZ77Store *store, ZopfliHash *h)
2035	{
2036	    size_t i, j, pos = 0;
2037	    size_t windowstart = instart > ZOPFLI_WINDOW_SIZE
2038	                             ? instart - ZOPFLI_WINDOW_SIZE
2039	                             : 0;
2040	
2041	    size_t total_length_test = 0;
2042	
2043	    if (instart == inend)
2044	        return;
2045	
2046	    ZopfliResetHash(ZOPFLI_WINDOW_SIZE, h);
2047	    ZopfliWarmupHash(in, windowstart, inend, h);
2048	    for (i = windowstart; i < instart; i++)
2049	    {
2050	        ZopfliUpdateHash(in, i, inend, h);
2051	    }
2052	
2053	    pos = instart;
2054	    for (i = 0; i < pathsize; i++)
2055	    {
2056	        unsigned short length = path[i];
2057	        unsigned short dummy_length;
2058	        unsigned short dist;
2059	        assert(pos < inend);
2060	
2061	        ZopfliUpdateHash(in, pos, inend, h);
2062	
2063	        /* Add to output. */
2064	        if (length >= ZOPFLI_MIN_MATCH)
2065	        {
2066	            /* Get the distance by recalculating longest match. The found length
2067	            should match the length from the path. */
2068	            ZopfliFindLongestMatch(s, h, in, pos, inend, length, 0,
2069	                                   &dist, &dummy_length);
2070	            assert(!(dummy_length != length && length > 2 && dummy_length > 2));
2071	            ZopfliVerifyLenDist(in, inend, pos, dist, length);
2072	            ZopfliStoreLitLenDist(length, dist, pos, store);
2073	            total_length_test += length;
2074	        }
2075	        else
2076	        {
2077	            length = 1;
2078	            ZopfliStoreLitLenDist(in[pos], 0, pos, store);
2079	            total_length_test++;
2080	        }
2081	
2082	        assert(pos + length <= inend);
2083	        for (j = 1; j < length; j++)
2084	        {
2085	            ZopfliUpdateHash(in, pos + j, inend, h);
2086	        }
2087	
2088	        pos += length;
2089	    }
2090	}
2091	
2092	/*
2093	Calculates the optimal path of lz77 lengths to use, from the calculated
2094	length_array. The length_array must contain the optimal length to reach that
2095	byte. The path will be filled with the lengths to use, so its data size will be
2096	the amount of lz77 symbols.
2097	*/
2098	static void TraceBackwards(size_t size, const unsigned short *length_array,
2099	                           unsigned short **path, size_t *pathsize)
2100	{
2101	    size_t index = size;
2102	    if (size == 0)
2103	        return;
2104	    for (;;)
2105	    {
2106	        ZOPFLI_APPEND_DATA(length_array[index], path, pathsize);
2107	        assert(length_array[index] <= index);
2108	        assert(length_array[index] <= ZOPFLI_MAX_MATCH);
2109	        assert(length_array[index] != 0);
2110	        index -= length_array[index];
2111	        if (index == 0)
2112	            break;
2113	    }
2114	
2115	    /* Mirror result. */
2116	    for (index = 0; index < *pathsize / 2; index++)
2117	    {
2118	        unsigned short temp = (*path)[index];
2119	        (*path)[index] = (*path)[*pathsize - index - 1];
2120	        (*path)[*pathsize - index - 1] = temp;
2121	    }
2122	}
2123	
2124	static size_t zopfli_min(size_t a, size_t b)
2125	{
2126	    return a < b ? a : b;
2127	}
2128	
2129	/*
2130	Finds the minimum possible cost this cost model can return for valid length and
2131	distance symbols.
2132	*/
2133	static double GetCostModelMinCost(CostModelFun *costmodel, void *costcontext)
2134	{
2135	    double mincost;
2136	    int bestlength = 0; /* length that has lowest cost in the cost model */
2137	    int bestdist = 0;   /* distance that has lowest cost in the cost model */
2138	    int i;
2139	    /*
2140	    Table of distances that have a different distance symbol in the deflate
2141	    specification. Each value is the first distance that has a new symbol. Only
2142	    different symbols affect the cost model so only these need to be checked.
2143	    See RFC 1951 section 3.2.5. Compressed blocks (length and distance codes).
2144	    */
2145	    static const int dsymbols[30] = {
2146	        1, 2, 3, 4, 5, 7, 9, 13, 17, 25, 33, 49, 65, 97, 129, 193, 257, 385, 513,
2147	        769, 1025, 1537, 2049, 3073, 4097, 6145, 8193, 12289, 16385, 24577};
2148	
2149	    mincost = ZOPFLI_LARGE_FLOAT;
2150	    for (i = 3; i < 259; i++)
2151	    {
2152	        double c = costmodel(i, 1, costcontext);
2153	        if (c < mincost)
2154	        {
2155	            bestlength = i;
2156	            mincost = c;
2157	        }
2158	    }
2159	
2160	    mincost = ZOPFLI_LARGE_FLOAT;
2161	    for (i = 0; i < 30; i++)
2162	    {
2163	        double c = costmodel(3, dsymbols[i], costcontext);
2164	        if (c < mincost)
2165	        {
2166	            bestdist = dsymbols[i];
2167	            mincost = c;
2168	        }
2169	    }
2170	
2171	    return costmodel(bestlength, bestdist, costcontext);
2172	}
2173	
2174	/*
2175	Performs the forward pass for "squeeze". Gets the most optimal length to reach
2176	every byte from a previous byte, using cost calculations.
2177	s: the ZopfliBlockState
2178	in: the input data array
2179	instart: where to start
2180	inend: where to stop (not inclusive)
2181	costmodel: function to calculate the cost of some lit/len/dist pair.
2182	costcontext: abstract context for the costmodel function
2183	length_array: output array of size (inend - instart) which will receive the best
2184	length to reach this byte from a previous byte.
2185	returns the cost that was, according to the costmodel, needed to get to the end.
2186	*/
2187	static double GetBestLengths(ZopfliBlockState *s,
2188	                             const unsigned char *in,
2189	                             size_t instart, size_t inend,
2190	                             CostModelFun *costmodel, void *costcontext,
2191	                             unsigned short *length_array,
2192	                             ZopfliHash *h, float *costs)
2193	{
2194	    /* Best cost to get here so far. */
2195	    size_t blocksize = inend - instart;
2196	    size_t i = 0, k, kend;
2197	    unsigned short leng;
2198	    unsigned short dist;
2199	    unsigned short sublen[259];
2200	    size_t windowstart = instart > ZOPFLI_WINDOW_SIZE
2201	                             ? instart - ZOPFLI_WINDOW_SIZE
2202	                             : 0;
2203	    double result;
2204	    double mincost = GetCostModelMinCost(costmodel, costcontext);
2205	    double mincostaddcostj;
2206	
2207	    if (instart == inend)
2208	        return 0;
2209	
2210	    ZopfliResetHash(ZOPFLI_WINDOW_SIZE, h);
2211	    ZopfliWarmupHash(in, windowstart, inend, h);
2212	    for (i = windowstart; i < instart; i++)
2213	    {
2214	        ZopfliUpdateHash(in, i, inend, h);
2215	    }
2216	
2217	    for (i = 1; i < blocksize + 1; i++)
2218	        costs[i] = ZOPFLI_LARGE_FLOAT;
2219	    costs[0] = 0; /* Because it's the start. */
2220	    length_array[0] = 0;
2221	
2222	    for (i = instart; i < inend; i++)
2223	    {
2224	        size_t j = i - instart; /* Index in the costs array and length_array. */
2225	        ZopfliUpdateHash(in, i, inend, h);
2226	
2227	        /* If we're in a long repetition of the same character and have more than
2228	        ZOPFLI_MAX_MATCH characters before and after our position. */
2229	        if (h->same[i & ZOPFLI_WINDOW_MASK] > ZOPFLI_MAX_MATCH * 2 && i > instart + ZOPFLI_MAX_MATCH + 1 && i + ZOPFLI_MAX_MATCH * 2 + 1 < inend && h->same[(i - ZOPFLI_MAX_MATCH) & ZOPFLI_WINDOW_MASK] > ZOPFLI_MAX_MATCH)
2230	        {
2231	            double symbolcost = costmodel(ZOPFLI_MAX_MATCH, 1, costcontext);
2232	            /* Set the length to reach each one to ZOPFLI_MAX_MATCH, and the cost to
2233	            the cost corresponding to that length. Doing this, we skip
2234	            ZOPFLI_MAX_MATCH values to avoid calling ZopfliFindLongestMatch. */
2235	            for (k = 0; k < ZOPFLI_MAX_MATCH; k++)
2236	            {
2237	                costs[j + ZOPFLI_MAX_MATCH] = costs[j] + symbolcost;
2238	                length_array[j + ZOPFLI_MAX_MATCH] = ZOPFLI_MAX_MATCH;
2239	                i++;
2240	                j++;
2241	                ZopfliUpdateHash(in, i, inend, h);
2242	            }
2243	        }
2244	
2245	        ZopfliFindLongestMatch(s, h, in, i, inend, ZOPFLI_MAX_MATCH, sublen,
2246	                               &dist, &leng);
2247	
2248	        /* Literal. */
2249	        if (i + 1 <= inend)
2250	        {
2251	            double newCost = costmodel(in[i], 0, costcontext) + costs[j];
2252	            assert(newCost >= 0);
2253	            if (newCost < costs[j + 1])
2254	            {
2255	                costs[j + 1] = newCost;
2256	                length_array[j + 1] = 1;
2257	            }
2258	        }
2259	        /* Lengths. */
2260	        kend = zopfli_min(leng, inend - i);
2261	        mincostaddcostj = mincost + costs[j];
2262	        for (k = 3; k <= kend; k++)
2263	        {
2264	            double newCost;
2265	
2266	            /* Calling the cost model is expensive, avoid this if we are already at
2267	            the minimum possible cost that it can return. */
2268	            if (costs[j + k] <= mincostaddcostj)
2269	                continue;
2270	
2271	            newCost = costmodel(k, sublen[k], costcontext) + costs[j];
2272	            assert(newCost >= 0);
2273	            if (newCost < costs[j + k])
2274	            {
2275	                assert(k <= ZOPFLI_MAX_MATCH);
2276	                costs[j + k] = newCost;
2277	                length_array[j + k] = k;
2278	            }
2279	        }
2280	    }
2281	
2282	    assert(costs[blocksize] >= 0);
