2709	        instead of zero (e.g. -5.973954e-17 with gcc 4.1.2 on Ubuntu 11.4). Clamp
2710	        it to zero. These floating point imprecisions do not affect the cost model
2711	        significantly so this is ok. */
2712	        if (bitlengths[i] < 0 && bitlengths[i] > -1e-5)
2713	            bitlengths[i] = 0;
2714	        assert(bitlengths[i] >= 0);
2715	    }
2716	}
