2718	/* Calculates the entropy of the statistics */
2719	static void CalculateStatistics(SymbolStats *stats)
2720	{
2721	    ZopfliCalculateEntropy(stats->litlens, ZOPFLI_NUM_LL, stats->ll_symbols);
2722	    ZopfliCalculateEntropy(stats->dists, ZOPFLI_NUM_D, stats->d_symbols);
2723	}
