2725	/* Appends the symbol statistics from the store. */
2726	static void GetStatistics(const ZopfliLZ77Store *store, SymbolStats *stats)
2727	{
2728	    size_t i;
2729	    for (i = 0; i < store->size; i++)
2730	    {
2731	        if (store->dists[i] == 0)
2732	        {
2733	            stats->litlens[store->litlens[i]]++;
2734	        }
2735	        else
2736	        {
2737	            stats->litlens[ZopfliGetLengthSymbol(store->litlens[i])]++;
2738	            stats->dists[ZopfliGetDistSymbol(store->dists[i])]++;
2739	        }
2740	    }
2741	    stats->litlens[256] = 1; /* End symbol. */
2742	
2743	    CalculateStatistics(stats);
2744	}
