2746	static void ClearStatFreqs(SymbolStats *stats)
2747	{
2748	    size_t i;
2749	    for (i = 0; i < ZOPFLI_NUM_LL; i++)
2750	        stats->litlens[i] = 0;
2751	    for (i = 0; i < ZOPFLI_NUM_D; i++)
2752	        stats->dists[i] = 0;
2753	}
