2755	/* Get random number: "Multiply-With-Carry" generator of G. Marsaglia */
2756	static unsigned int Ran(RanState *state)
2757	{
2758	    state->m_z = 36969 * (state->m_z & 65535) + (state->m_z >> 16);
2759	    state->m_w = 18000 * (state->m_w & 65535) + (state->m_w >> 16);
2760	    return (state->m_z << 16) + state->m_w; /* 32-bit result. */
2761	}
2762	
2763	static void RandomizeFreqs(RanState *state, size_t *freqs, int n)
2764	{
2765	    int i;
2766	    for (i = 0; i < n; i++)
2767	    {
2768	        if ((Ran(state) >> 4) % 3 == 0)
2769	            freqs[i] = freqs[Ran(state) % n];
2770	    }
2771	}
2772	
2773	static void RandomizeStatFreqs(RanState *state, SymbolStats *stats)
2774	{
2775	    RandomizeFreqs(state, stats->litlens, ZOPFLI_NUM_LL);
2776	    RandomizeFreqs(state, stats->dists, ZOPFLI_NUM_D);
2777	    stats->litlens[256] = 1; /* End symbol. */
2778	}
2779	
2780	static void InitRanState(RanState *state)
2781	{
2782	    state->m_w = 1;
2783	    state->m_z = 2;
2784	}
2785	
2786	/* Adds the bit lengths. */
2787	static void AddWeighedStatFreqs(const SymbolStats *stats1, double w1,
2788	                                const SymbolStats *stats2, double w2,
2789	                                SymbolStats *result)
2790	{
2791	    size_t i;
2792	    for (i = 0; i < ZOPFLI_NUM_LL; i++)
2793	    {
2794	        result->litlens[i] =
2795	            (size_t)(stats1->litlens[i] * w1 + stats2->litlens[i] * w2);
2796	    }
2797	    for (i = 0; i < ZOPFLI_NUM_D; i++)
2798	    {
2799	        result->dists[i] =
2800	            (size_t)(stats1->dists[i] * w1 + stats2->dists[i] * w2);
2801	    }
2802	    result->litlens[256] = 1; /* End symbol. */
2803	}
