2805	static size_t CeilDiv(size_t a, size_t b)
2806	{
2807	    return (a + b - 1) / b;
2808	}
2809	
2810	void ZopfliCopyLZ77Store(
2811	    const ZopfliLZ77Store *source, ZopfliLZ77Store *dest)
2812	{
2813	    size_t i;
2814	    size_t llsize = ZOPFLI_NUM_LL * CeilDiv(source->size, ZOPFLI_NUM_LL);
2815	    size_t dsize = ZOPFLI_NUM_D * CeilDiv(source->size, ZOPFLI_NUM_D);
2816	    ZopfliCleanLZ77Store(dest);
2817	    ZopfliInitLZ77Store(source->data, dest);
2818	    dest->litlens =
2819	        (unsigned short *)malloc(sizeof(*dest->litlens) * source->size);
2820	    dest->dists = (unsigned short *)malloc(sizeof(*dest->dists) * source->size);
2821	    dest->pos = (size_t *)malloc(sizeof(*dest->pos) * source->size);
2822	    dest->ll_symbol =
2823	        (unsigned short *)malloc(sizeof(*dest->ll_symbol) * source->size);
2824	    dest->d_symbol =
2825	        (unsigned short *)malloc(sizeof(*dest->d_symbol) * source->size);
2826	    dest->ll_counts = (size_t *)malloc(sizeof(*dest->ll_counts) * llsize);
2827	    dest->d_counts = (size_t *)malloc(sizeof(*dest->d_counts) * dsize);
2828	
2829	    /* Allocation failed. */
2830	    if (!dest->litlens || !dest->dists)
2831	        exit(-1);
2832	    if (!dest->pos)
2833	        exit(-1);
2834	    if (!dest->ll_symbol || !dest->d_symbol)
2835	        exit(-1);
2836	    if (!dest->ll_counts || !dest->d_counts)
2837	        exit(-1);
2838	
2839	    dest->size = source->size;
2840	    for (i = 0; i < source->size; i++)
2841	    {
2842	        dest->litlens[i] = source->litlens[i];
2843	        dest->dists[i] = source->dists[i];
2844	        dest->pos[i] = source->pos[i];
2845	        dest->ll_symbol[i] = source->ll_symbol[i];
2846	        dest->d_symbol[i] = source->d_symbol[i];
2847	    }
2848	    for (i = 0; i < llsize; i++)
2849	    {
2850	        dest->ll_counts[i] = source->ll_counts[i];
2851	    }
2852	    for (i = 0; i < dsize; i++)
2853	    {
2854	        dest->d_counts[i] = source->d_counts[i];
2855	    }
2856	}
