2858	static void CopyStats(SymbolStats *source, SymbolStats *dest)
2859	{
2860	    memcpy(dest->litlens, source->litlens,
2861	           ZOPFLI_NUM_LL * sizeof(dest->litlens[0]));
2862	    memcpy(dest->dists, source->dists, ZOPFLI_NUM_D * sizeof(dest->dists[0]));
2863	
2864	    memcpy(dest->ll_symbols, source->ll_symbols,
2865	           ZOPFLI_NUM_LL * sizeof(dest->ll_symbols[0]));
2866	    memcpy(dest->d_symbols, source->d_symbols,
2867	           ZOPFLI_NUM_D * sizeof(dest->d_symbols[0]));
