2880	/*
2881	Calculates lit/len and dist pairs for given data.
2882	If instart is larger than 0, it uses values before instart as starting
2883	dictionary.
2884	*/
2885	void ZopfliLZ77Optimal(ZopfliBlockState *s,
2886	                       const unsigned char *in, size_t instart, size_t inend,
2887	                       int numiterations,
2888	                       ZopfliLZ77Store *store)
2889	{
2890	    /* Dist to get to here with smallest cost. */
2891	    size_t blocksize = inend - instart;
2892	    unsigned short *length_array =
2893	        (unsigned short *)malloc(sizeof(unsigned short) * (blocksize + 1));
2894	    unsigned short *path = 0;
2895	    size_t pathsize = 0;
2896	    ZopfliLZ77Store currentstore;
2897	    ZopfliHash hash;
2898	    ZopfliHash *h = &hash;
2899	    SymbolStats stats, beststats, laststats;
2900	    int i;
2901	    float *costs = (float *)malloc(sizeof(float) * (blocksize + 1));
2902	    double cost;
2903	    double bestcost = ZOPFLI_LARGE_FLOAT;
2904	    double lastcost = 0;
2905	    /* Try randomizing the costs a bit once the size stabilizes. */
2906	    RanState ran_state;
2907	    int lastrandomstep = -1;
2908	
2909	    if (!costs)
2910	        exit(-1); /* Allocation failed. */
2911	    if (!length_array)
2912	        exit(-1); /* Allocation failed. */
2913	
2914	    InitRanState(&ran_state);
2915	    InitStats(&stats);
2916	    ZopfliInitLZ77Store(in, &currentstore);
2917	    ZopfliAllocHash(ZOPFLI_WINDOW_SIZE, h);
2918	
2919	    /* Do regular deflate, then loop multiple shortest path runs, each time using
2920	    the statistics of the previous run. */
2921	
2922	    /* Initial run. */
2923	    ZopfliLZ77Greedy(s, in, instart, inend, &currentstore, h);
2924	    GetStatistics(&currentstore, &stats);
2925	
2926	    /* Repeat statistics with each time the cost model from the previous stat
2927	    run. */
2928	    for (i = 0; i < numiterations; i++)
2929	    {
2930	        ZopfliCleanLZ77Store(&currentstore);
2931	        ZopfliInitLZ77Store(in, &currentstore);
2932	        LZ77OptimalRun(s, in, instart, inend, &path, &pathsize,
2933	                       length_array, GetCostStat, (void *)&stats,
2934	                       &currentstore, h, costs);
2935	        cost = ZopfliCalculateBlockSize(&currentstore, 0, currentstore.size, 2);
2936	        if (s->options->verbose_more || (s->options->verbose && cost < bestcost))
2937	        {
2938	            fprintf(stderr, "Iteration %d: %d bit\n", i, (int)cost);
2939	        }
2940	        if (cost < bestcost)
2941	        {
2942	            /* Copy to the output store. */
2943	            ZopfliCopyLZ77Store(&currentstore, store);
2944	            CopyStats(&stats, &beststats);
2945	            bestcost = cost;
2946	        }
2947	        CopyStats(&stats, &laststats);
2948	        ClearStatFreqs(&stats);
2949	        GetStatistics(&currentstore, &stats);
2950	        if (lastrandomstep != -1)
2951	        {
2952	            /* This makes it converge slower but better. Do it only once the
2953	            randomness kicks in so that if the user does few iterations, it gives a
2954	            better result sooner. */
2955	            AddWeighedStatFreqs(&stats, 1.0, &laststats, 0.5, &stats);
2956	            CalculateStatistics(&stats);
2957	        }
2958	        if (i > 5 && cost == lastcost)
2959	        {
2960	            CopyStats(&beststats, &stats);
2961	            RandomizeStatFreqs(&ran_state, &stats);
2962	            CalculateStatistics(&stats);
2963	            lastrandomstep = i;
2964	        }
2965	        lastcost = cost;
2966	    }
2967	
2968	    free(length_array);
2969	    free(path);
2970	    free(costs);
2971	    ZopfliCleanLZ77Store(&currentstore);
2972	    ZopfliCleanHash(h);
2973	}
