2975	/*
2976	Finds next block to try to split, the largest of the available ones.
2977	The largest is chosen to make sure that if only a limited amount of blocks is
2978	requested, their sizes are spread evenly.
2979	lz77size: the size of the LL77 data, which is the size of the done array here.
2980	done: array indicating which blocks starting at that position are no longer
2981	splittable (splitting them increases rather than decreases cost).
2982	splitpoints: the splitpoints found so far.
2983	npoints: the amount of splitpoints found so far.
2984	lstart: output variable, giving start of block.
2985	lend: output variable, giving end of block.
2986	returns 1 if a block was found, 0 if no block found (all are done).
2987	*/
2988	static int FindLargestSplittableBlock(
2989	    size_t lz77size, const unsigned char *done,
2990	    const size_t *splitpoints, size_t npoints,
2991	    size_t *lstart, size_t *lend)
2992	{
2993	    size_t longest = 0;
2994	    int found = 0;
2995	    size_t i;
2996	    for (i = 0; i <= npoints; i++)
2997	    {
2998	        size_t start = i == 0 ? 0 : splitpoints[i - 1];
2999	        size_t end = i == npoints ? lz77size - 1 : splitpoints[i];
3000	        if (!done[start] && end - start > longest)
3001	        {
3002	            *lstart = start;
3003	            *lend = end;
3004	            found = 1;
3005	            longest = end - start;
3006	        }
3007	    }
3008	    return found;
3009	}
