3014	static void PrintBlockSplitPoints(const ZopfliLZ77Store *lz77,
3015	                                  const size_t *lz77splitpoints,
3016	                                  size_t nlz77points)
3017	{
3018	    size_t *splitpoints = 0;
3019	    size_t npoints = 0;
3020	    size_t i;
3021	    /* The input is given as lz77 indices, but we want to see the uncompressed
3022	    index values. */
3023	    size_t pos = 0;
