3025	    {
3026	        for (i = 0; i < lz77->size; i++)
3027	        {
3028	            size_t length = lz77->dists[i] == 0 ? 1 : lz77->litlens[i];
3029	            if (lz77splitpoints[npoints] == i)
3030	            {
3031	                ZOPFLI_APPEND_DATA(pos, &splitpoints, &npoints);
3032	                if (npoints == nlz77points)
