3055	static void AddSorted(size_t value, size_t **out, size_t *outsize)
3056	{
3057	    size_t i;
3058	    ZOPFLI_APPEND_DATA(value, out, outsize);
3059	    for (i = 0; i + 1 < *outsize; i++)
3060	    {
3061	        if ((*out)[i] > value)
3062	        {
3063	            size_t j;
3064	            for (j = *outsize - 1; j > i; j--)
3065	            {
3066	                (*out)[j] = (*out)[j - 1];
3067	            }
3068	            (*out)[i] = value;
3069	            break;
3070	        }
3071	    }
3072	}
