3074	/* Try to find minimum faster by recursively checking multiple points. */
3075	#define NUM 9 /* Good value: 9. */
3076	
3077	/*
3078	Finds minimum of function f(i) where is is of type size_t, f(i) is of type
3079	double, i is in range start-end (excluding end).
3080	Outputs the minimum value in *smallest and returns the index of this value.
3081	*/
3082	static size_t FindMinimum(FindMinimumFun f, void *context,
3083	                          size_t start, size_t end, double *smallest)
3084	{
3085	    if (end - start < 1024)
3086	    {
3087	        double best = ZOPFLI_LARGE_FLOAT;
3088	        size_t result = start;
3089	        size_t i;
3090	        for (i = start; i < end; i++)
3091	        {
3092	            double v = f(i, context);
3093	            if (v < best)
3094	            {
3095	                best = v;
3096	                result = i;
3097	            }
3098	        }
3099	        *smallest = best;
3100	        return result;
3101	    }
3102	    else
3103	    {
3104	        /* Try to find minimum faster by recursively checking multiple points. */
3105	#define NUM 9 /* Good value: 9. */
3106	        size_t i;
3107	        size_t p[NUM];
3108	        double vp[NUM];
3109	        size_t besti;
3110	        double best;
3111	        double lastbest = ZOPFLI_LARGE_FLOAT;
3112	        size_t pos = start;
3113	
3114	        for (;;)
3115	        {
3116	            if (end - start <= NUM)
3117	                break;
3118	
3119	            for (i = 0; i < NUM; i++)
3120	            {
3121	                p[i] = start + (i + 1) * ((end - start) / (NUM + 1));
3122	                vp[i] = f(p[i], context);
3123	            }
3124	            besti = 0;
3125	            best = vp[0];
3126	            for (i = 1; i < NUM; i++)
3127	            {
3128	                if (vp[i] < best)
3129	                {
3130	                    best = vp[i];
3131	                    besti = i;
3132	                }
3133	            }
3134	            if (best > lastbest)
3135	                break;
3136	
3137	            start = besti == 0 ? start : p[besti - 1];
3138	            end = besti == NUM - 1 ? end : p[besti + 1];
3139	
3140	            pos = p[besti];
3141	            lastbest = best;
3142	        }
3143	        *smallest = lastbest;
3144	        return pos;
3145	#undef NUM
3146	    }
3147	}
