3149	/*
3150	Does blocksplitting on LZ77 data.
3151	The output splitpoints are indices in the LZ77 data.
3152	maxblocks: set a limit to the amount of blocks. Set to 0 to mean no limit.
3153	*/
3154	void ZopfliBlockSplitLZ77(const ZopfliOptions *options,
3155	                          const ZopfliLZ77Store *lz77, size_t maxblocks,
3156	                          size_t **splitpoints, size_t *npoints)
3157	{
3158	    size_t lstart, lend;
3159	    size_t i;
3160	    size_t llpos = 0;
3161	    size_t numblocks = 1;
3162	    unsigned char *done;
3163	    double splitcost, origcost;
3164	
3165	    if (lz77->size < 10)
3166	        return; /* This code fails on tiny files. */
3167	
3168	    done = (unsigned char *)malloc(lz77->size);
3169	    if (!done)
3170	        exit(-1); /* Allocation failed. */
3171	    for (i = 0; i < lz77->size; i++)
3172	        done[i] = 0;
3173	
3174	    lstart = 0;
3175	    lend = lz77->size;
3176	    for (;;)
3177	    {
3178	        SplitCostContext c;
3179	
3180	        if (maxblocks > 0 && numblocks >= maxblocks)
3181	        {
3182	            break;
3183	        }
3184	
3185	        c.lz77 = lz77;
3186	        c.start = lstart;
3187	        c.end = lend;
3188	        assert(lstart < lend);
3189	        llpos = FindMinimum(SplitCost, &c, lstart + 1, lend, &splitcost);
3190	
3191	        assert(llpos > lstart);
3192	        assert(llpos < lend);
3193	
3194	        origcost = EstimateCost(lz77, lstart, lend);
3195	
3196	        if (splitcost > origcost || llpos == lstart + 1 || llpos == lend)
3197	        {
3198	            done[lstart] = 1;
3199	        }
3200	        else
3201	        {
3202	            AddSorted(llpos, splitpoints, npoints);
3203	            numblocks++;
3204	        }
3205	
3206	        if (!FindLargestSplittableBlock(
3207	                lz77->size, done, *splitpoints, *npoints, &lstart, &lend))
3208	        {
3209	            break; /* No further split will probably reduce compression. */
3210	        }
3211	
3212	        if (lend - lstart < 10)
3213	        {
3214	            break;
3215	        }
3216	    }
3217	
3218	    if (options->verbose)
3219	    {
3220	        PrintBlockSplitPoints(lz77, *splitpoints, *npoints);
3221	    }
3222	
3223	    free(done);
3224	}
