3226	/*
3227	Does blocksplitting on uncompressed data.
3228	The output splitpoints are indices in the uncompressed bytes.
3229	
3230	options: general program options.
3231	in: uncompressed input data
3232	instart: where to start splitting
3233	inend: where to end splitting (not inclusive)
3234	maxblocks: maximum amount of blocks to split into, or 0 for no limit
3235	splitpoints: dynamic array to put the resulting split point coordinates into.
3236	The coordinates are indices in the input array.
3237	npoints: pointer to amount of splitpoints, for the dynamic array. The amount of
3238	blocks is the amount of splitpoitns + 1.
3239	*/
3240	void ZopfliBlockSplit(const ZopfliOptions *options,
3241	                      const unsigned char *in, size_t instart, size_t inend,
3242	                      size_t maxblocks, size_t **splitpoints, size_t *npoints)
3243	{
3244	    size_t pos = 0;
3245	    size_t i;
3246	    ZopfliBlockState s;
3247	    size_t *lz77splitpoints = 0;
3248	    size_t nlz77points = 0;
3249	    ZopfliLZ77Store store;
3250	    ZopfliHash hash;
3251	    ZopfliHash *h = &hash;
3252	
3253	    ZopfliInitLZ77Store(in, &store);
3254	    ZopfliInitBlockState(options, instart, inend, 0, &s);
3255	    ZopfliAllocHash(ZOPFLI_WINDOW_SIZE, h);
3256	
3257	    *npoints = 0;
3258	    *splitpoints = 0;
3259	
3260	    /* Unintuitively, Using a simple LZ77 method here instead of ZopfliLZ77Optimal
3261	    results in better blocks. */
3262	    ZopfliLZ77Greedy(&s, in, instart, inend, &store, h);
3263	
3264	    ZopfliBlockSplitLZ77(options,
3265	                         &store, maxblocks,
3266	                         &lz77splitpoints, &nlz77points);
3267	
3268	    /* Convert LZ77 positions to positions in the uncompressed input. */
3269	    pos = instart;
3270	    if (nlz77points > 0)
3271	    {
3272	        for (i = 0; i < store.size; i++)
3273	        {
3274	            size_t length = store.dists[i] == 0 ? 1 : store.litlens[i];
3275	            if (lz77splitpoints[*npoints] == i)
3276	            {
3277	                ZOPFLI_APPEND_DATA(pos, splitpoints, npoints);
3278	                if (*npoints == nlz77points)
3279	                    break;
3280	            }
3281	            pos += length;
3282	        }
3283	    }
3284	    assert(*npoints == nlz77points);
3285	
3286	    free(lz77splitpoints);
3287	    ZopfliCleanBlockState(&s);
3288	    ZopfliCleanLZ77Store(&store);
