3421	/*
3422	Compresses according to the deflate specification and append the compressed
3423	result to the output.
3424	This function will usually output multiple deflate blocks. If final is 1, then
3425	the final bit will be set on the last block.
3426	
3427	options: global program options
3428	btype: the deflate block type. Use 2 for best compression.
3429	-0: non compressed blocks (00)
3430	-1: blocks with fixed tree (01)
3431	-2: blocks with dynamic tree (10)
3432	final: whether this is the last section of the input, sets the final bit to the
3433	last deflate block.
3434	in: the input bytes
3435	insize: number of input bytes
3436	bp: bit pointer for the output array. This must initially be 0, and for
3437	consecutive calls must be reused (it can have values from 0-7). This is
3438	because deflate appends blocks as bit-based data, rather than on byte
3439	boundaries.
3440	out: pointer to the dynamic output array to which the result is appended. Must
3441	be freed after use.
3442	outsize: pointer to the dynamic output array size.
3443	*/
3444	void ZopfliDeflate(const ZopfliOptions *options, int btype, int final,
3445	                   const unsigned char *in, size_t insize,
3446	                   unsigned char *bp, unsigned char **out, size_t *outsize)
3447	{
3448	    size_t offset = *outsize;
3449	    size_t i = 0;
3450	    do
3451	    {
3452	        int masterfinal = (i + ZOPFLI_MASTER_BLOCK_SIZE >= insize);
3453	        int final2 = final && masterfinal;
3454	        size_t size = masterfinal ? insize - i : ZOPFLI_MASTER_BLOCK_SIZE;
3455	        ZopfliDeflatePart(options, btype, final2,
3456	                          in, i, i + size, bp, out, outsize);
3457	        i += size;
3458	    } while (i < insize);
3459	    if (options->verbose)
3460	    {
3461	        fprintf(stderr,
3462	                "Original Size: %lu, Deflate: %lu, Compression: %.2f%%\n",
3463	                (unsigned long)insize, (unsigned long)(*outsize - offset),
3464	                100.0 * (double)(insize - (*outsize - offset)) / (double)insize);
3465	    }
3466	}
